using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now sets the UTF-8 flag and
        // encodes names as UTF-8. The legacy Java consumer expects Shift-JIS,
        // so specify the encoding explicitly to avoid the UTF-8 flag being set.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create,
            Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("Ńā¼ŃāØŃā╝Ńāł/µ£łµ¼Ī.csv");  // Japanese path
        archive.CreateEntry("donn├®es/r├®sum├®.txt"); // French accented
